function calcSetBonuses(inventory, equipped) {
  const equippedIds = new Set(Object.values(equipped).filter(Boolean));
  const equippedItemIds = [];
  for (const invId of equippedIds) {
    const inv = inventory.find(i=>i.invId===invId);
    if (inv) equippedItemIds.push(inv.itemId);
  }
  const results = [];
  for (const [setId, setDef] of Object.entries(ITEM_SETS)) {
    const matches = setDef.items.filter(id => equippedItemIds.includes(id));
    if (matches.length >= 2) {
      const keys = Object.keys(setDef.bonuses).map(Number).filter(k=>k<=matches.length);
      const bonus = keys.length ? setDef.bonuses[Math.max(...keys)] : 0;
      results.push({setId,name:setDef.name,color:setDef.color,count:matches.length,total:setDef.items.length,bonus});
    }
  }
  return results;
}

function itemIcon(item, size) {
  const sz = size || '32px';
  const px = parseInt(sz) || 32;
  if (item && item.img) {
    return `<img src="${item.img}" style="width:${sz};height:${sz};image-rendering:pixelated;display:block">`;
  }
  const emoji = (item ? SLOT_ICONS[item.slot] : null) || '📦';
  return `<span style="font-size:${Math.round(px*0.75)}px;line-height:1;display:block;text-align:center">${emoji}</span>`;
}
function slotIcon(slot, size) {
  const px = parseInt(size) || 28;
  const emoji = SLOT_ICONS[slot] || '?';
  return `<span style="font-size:${Math.round(px*0.85)}px;line-height:1;opacity:.45">${emoji}</span>`;
}

let invState = { inventory:[], equipped:{}, spins:0, milestoneTrades:0, visible:false, activeTab:'inventory' };
let marketState = [];

function getToken(){ return window.FM_TOKEN || window.ME?.token || window.ME?.id || localStorage.getItem('fm_token') || ''; }

// ── Panel Toggle ──────────────────────────────────────────────────────────────
window.toggleInvPanel = function(){
  // Navigate to Store tab → Inventory sub-tab
  var storeBtn = document.querySelector('.tab[data-tab="store"]');
  if(storeBtn) storeBtn.click();
  if(window.storeSubTab) window.storeSubTab('inventory');
  loadInventory();
};

window.toggleSlotModal = function(){
  // Navigate to Store tab → Slots sub-tab
  var storeBtn = document.querySelector('.tab[data-tab="store"]');
  if(storeBtn) storeBtn.click();
  if(window.storeSubTab) window.storeSubTab('slots');
  loadInventory().catch(function(){});
};

window.invTab = function(tab){
  invState.activeTab = tab;
  if(tab==='inventory' && window.storeSubTab) window.storeSubTab('inventory');
  if(tab==='market' && window.storeSubTab) window.storeSubTab('fbay');
};

window._loadInv = loadInventory;

// ── Inventory ─────────────────────────────────────────────────────────────────
async function loadInventory(){
  const token = getToken(); if(!token) return;
  try{
    const r = await fetch('/api/items/inventory?token='+token);
    const d = await r.json();
    if(!d.ok) return;
    invState.inventory = d.inventory || [];
    invState.equipped  = d.equipped  || {};
    invState.spins     = d.spins     || 0;
    invState.milestoneTrades = d.milestoneTrades || 0;
    renderInventory();
    updateSlotModalCount();
    updateListSelect();
  }catch(e){ console.error('inv load',e); }
}

function rarityBadge(rarity){
  const c = RARITY_COLORS[rarity]||'#888';
  return `<span style="font-size:.58rem;color:${c};border:1px solid ${c}44;padding:1px 5px;border-radius:3px;text-transform:uppercase;letter-spacing:.06em">${rarity}</span>`;
}

function renderInventory(){
  const equippedEl = document.getElementById('equippedGrid');
  const bagEl      = document.getElementById('bagGrid');
  const passiveEl  = document.getElementById('invPassiveTotal');
  const countEl    = document.getElementById('invBagCount');
  if(!equippedEl||!bagEl) return;

  // Calculate total passive
  let totalPassive = 0;
  const equippedInvIds = new Set(Object.values(invState.equipped).filter(Boolean));
  for(const invId of equippedInvIds){
    const inv = invState.inventory.find(i=>i.invId===invId);
    if(inv) totalPassive += (inv.passive||0);
  }
  if(passiveEl) passiveEl.textContent = '+'+totalPassive+' Ƒ/30min';

  // Set bonus display
  const setResults = calcSetBonuses(invState.inventory, invState.equipped);
  const setBonusEl = document.getElementById('invSetBonuses');
  if(setBonusEl){
    if(setResults.length){
      setBonusEl.innerHTML = setResults.map(s=>
        `<div style="display:flex;justify-content:space-between;align-items:center;padding:3px 6px;background:${s.color}11;border-left:2px solid ${s.color};border-radius:3px;margin-bottom:3px;font-size:.68rem">
           <span style="color:${s.color};font-weight:600">${s.name}</span>
           <span style="color:#aaa">${s.count}/${s.total} pieces</span>
           <span style="color:${s.color}">+${s.bonus} Ƒ/30min</span>
         </div>`
      ).join('');
      setBonusEl.style.display='block';
    } else {
      setBonusEl.innerHTML='';
      setBonusEl.style.display='none';
    }
  }

  // Equipped grid
  let eHtml = '';
  for(const [slot, label] of Object.entries(SLOT_LABELS)){
    const invId = invState.equipped[slot];
    const inv   = invId ? invState.inventory.find(i=>i.invId===invId) : null;
    const item  = inv ? ITEM_CATALOG_CLIENT[inv.itemId] : null;
    const rc    = item ? (RARITY_COLORS[item.rarity]||'#888') : '#333';
    eHtml += `<div class="equip-slot ${item?'filled':''}" onclick="openEquipMenu('${slot}')" title="Click to change">
      <div style="width:32px;height:32px;flex-shrink:0;display:flex;align-items:center;justify-content:center">${item ? itemIcon(item,'28px') : slotIcon(slot,'28px')}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:.62rem;color:#553333;letter-spacing:.07em;text-transform:uppercase">${label}</div>
        ${item
          ? `<div style="font-size:.72rem;color:${rc};font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${item.name}</div>
             <div style="font-size:.62rem;color:#553333">+${item.passive} Ƒ/30min</div>`
          : `<div style="font-size:.68rem;color:#332222;font-style:italic">Empty</div>`
        }
      </div>
      ${item ? `<span style="font-size:.58rem;color:#553333;cursor:pointer" onclick="event.stopPropagation();unequipSlot('${slot}')">✕</span>` : ''}
    </div>`;
  }
  equippedEl.innerHTML = eHtml;

  // Bag (unequipped items)
  const bag = invState.inventory.filter(i=>!equippedInvIds.has(i.invId));
  if(countEl) countEl.textContent = '('+bag.length+')';
  if(!bag.length){ bagEl.innerHTML='<div style="color:#332222;font-size:.72rem;padding:8px">No items yet. Spin to get some.</div>'; return; }
  bagEl.innerHTML = bag.map(inv=>{
    const item = ITEM_CATALOG_CLIENT[inv.itemId]||{name:inv.itemId,rarity:'common',passive:0,slot:'?'};
    const rc = RARITY_COLORS[item.rarity]||'#888';
    return `<div class="bag-item" onclick="equipFromBag('${inv.invId}','${item.slot}')" title="Click to equip · ${item.name}">
      <div style="margin-bottom:2px;width:32px;height:32px;display:flex;align-items:center;justify-content:center;margin:0 auto 2px">${itemIcon(item,'32px')}</div>
      <div style="font-size:.62rem;color:${rc};font-weight:500;line-height:1.2">${item.name}</div>
      <div style="font-size:.58rem;color:#443333;margin-top:2px">+${item.passive} Ƒ</div>
      ${rarityBadge(item.rarity)}
    </div>`;
  }).join('');
}

window.equipFromBag = async function(invId, slot){
  const token = getToken(); if(!token) return;
  try{
    const r = await fetch('/api/items/equip',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,invId,slot})});
    const d = await r.json();
    if(d.ok){ invState.equipped[slot]=invId; renderInventory(); try{showToast('Equipped!','#1D9E75');}catch(_){} }
    else{ try{showToast('Could not equip: '+d.error,'#ff4444');}catch(_){} }
  }catch(e){}
};

window.unequipSlot = async function(slot){
  const token = getToken(); if(!token) return;
  try{
    await fetch('/api/items/unequip',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,slot})});
    invState.equipped[slot]=null; renderInventory();
  }catch(e){}
};

window.openEquipMenu = function(slot){
  const compatible = invState.inventory.filter(i=>{
    const item = ITEM_CATALOG_CLIENT[i.itemId];
    return item && item.slot===slot && !Object.values(invState.equipped).includes(i.invId);
  });
  if(!compatible.length){ try{showToast('No '+SLOT_LABELS[slot]+' items in bag','#ff9900');}catch(_){} return; }
  // Auto-equip best passive item for that slot
  compatible.sort((a,b)=>(b.passive||0)-(a.passive||0));
  equipFromBag(compatible[0].invId, slot);
};

// ── Slot Machine Modal ────────────────────────────────────────────────────────
const SLOT_ICONS_LIST = ['🎩','👓','👕','⌚','👖','👟','🚗','🏠','📿','💎','⭐','🔥','💰','🃏','❤️'];

// toggleSlotModal defined above — navigates to store tab slots pane

function updateSlotModalCount(){
  const el = document.getElementById('slotModalSpinCount');
  const navEl = document.getElementById('slotNavSpinCount');
  if(el) el.textContent = invState.spins || 0;
  if(navEl) navEl.textContent = invState.spins > 0 ? `(${invState.spins})` : '';
  // Milestone progress tracker
  const progress = (invState.milestoneTrades || 0) % 9;
  const countEl = document.getElementById('slotMilestoneCount');
  const barEl = document.getElementById('slotMilestoneBar');
  if(countEl) countEl.textContent = progress;
  if(barEl) barEl.style.width = ((progress / 9) * 100) + '%';
}

window.doSlotSpin = async function(){
  const token = getToken();
  if(!token){ try{showToast('Login required','#ff4444');}catch(_){} return; }
  if((invState.spins||0) < 1){ try{showToast('No spins remaining — complete 9 day trades to earn one','#ff9900');}catch(_){} return; }

  const btn = document.getElementById('slotModalBtn');
  if(btn){ btn.disabled=true; btn.textContent='Spinning…'; }

  const reelIds = ['slotReel1','slotReel2','slotReel3'];
  reelIds.forEach(id=>{ const el=document.getElementById(id); if(el) el.classList.add('spinning'); });

  try{
    const r = await fetch('/api/items/spin',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token})});
    const d = await r.json();

    setTimeout(()=>{
      // Resolve full client-side item (has base64 img) from server response id
      const clientItem = d.ok ? (ITEM_CATALOG_CLIENT[d.item?.id] || d.item) : null;

      reelIds.forEach((id,i)=>{
        const el=document.getElementById(id); if(!el) return;
        el.classList.remove('spinning');
        const span = el.querySelector('span');
        if(d.ok && clientItem && clientItem.img){
          // Middle reel shows the item art; outer reels show slot emoji
          if(i===1){
            span.innerHTML = `<img src="${clientItem.img}" style="width:40px;height:40px;image-rendering:pixelated;vertical-align:middle">`;
          } else {
            span.innerHTML = SLOT_ICONS[clientItem.slot]||'📦';
          }
        } else {
          span.innerHTML = SLOT_ICONS_LIST[Math.floor(Math.random()*SLOT_ICONS_LIST.length)];
        }
      });

      const rb = document.getElementById('slotModalResult');
      if(rb){
        if(d.ok){
          const rc = RARITY_COLORS[clientItem?.rarity]||'#888';
          rb.innerHTML = `
            <div style="border:1px solid ${rc}44;border-radius:10px;padding:14px 20px;background:${rc}0d;display:inline-block;min-width:180px">
              <div style="width:64px;height:64px;margin:0 auto 6px;display:flex;align-items:center;justify-content:center">${itemIcon(clientItem,'64px')}</div>
              <div style="font-size:1.05rem;font-weight:500;color:${rc}">${clientItem?.name||d.item?.name||'Unknown'}</div>
              <div style="font-size:.68rem;color:${rc}99;letter-spacing:.08em;margin-top:2px">${(clientItem?.rarity||d.item?.rarity||'').toUpperCase()}</div>
              <div style="font-size:.65rem;color:#553333;margin-top:6px">+${clientItem?.passive||d.item?.passive||0} Ƒ/30min · Added to inventory</div>
            </div>`;
          invState.spins = d.spinsRemaining ?? 0;
          updateSlotModalCount();
          loadInventory();
        } else {
          rb.innerHTML = `<div style="color:#ff4444;font-size:.82rem">${d.error==='no_spins'?'No spins remaining.':'Spin failed. Try again.'}</div>`;
        }
      }
      if(btn){ btn.disabled=false; btn.textContent='Spin'; }
    }, 900);

  }catch(e){
    reelIds.forEach(id=>{ const el=document.getElementById(id); if(el) el.classList.remove('spinning'); });
    if(btn){ btn.disabled=false; btn.textContent='Spin'; }
  }
};

// ── Market ────────────────────────────────────────────────────────────────────
const RARITY_ORDER = {common:0,uncommon:1,rare:2,epic:3,legendary:4};

window.loadMarket = async function(){
  const el = document.getElementById('marketListings'); if(!el) return;
  el.innerHTML = '<div style="color:#443333;font-size:.73rem;padding:8px">Loading…</div>';
  try{
    const r = await fetch('/api/items/market');
    const d = await r.json();
    if(!d.ok){ el.innerHTML='<div style="color:#ff4444;font-size:.73rem">Failed to load</div>'; return; }
    marketState = d.listings || [];
    applyMarketFilters();
  }catch(e){ el.innerHTML='<div style="color:#ff4444;font-size:.73rem">Error loading market</div>'; }
};

window.applyMarketFilters = function(){
  const el = document.getElementById('marketListings'); if(!el) return;
  const slotF   = document.getElementById('mktFilterSlot')?.value   || '';
  const rarityF = document.getElementById('mktFilterRarity')?.value || '';
  const sortBy  = document.getElementById('mktSortBy')?.value       || 'newest';

  let filtered = (marketState||[]).map(l => ({
    ...l, itemMeta: ITEM_CATALOG_CLIENT[l.item_id]||{name:l.item_id,rarity:'common',passive:0,slot:'?'},
  }));

  if(slotF)   filtered = filtered.filter(l => l.itemMeta.slot   === slotF);
  if(rarityF) filtered = filtered.filter(l => l.itemMeta.rarity === rarityF);

  filtered.sort((a,b) => {
    if(sortBy === 'price_asc')  return a.price - b.price;
    if(sortBy === 'price_desc') return b.price - a.price;
    if(sortBy === 'rarity')     return (RARITY_ORDER[b.itemMeta.rarity]||0) - (RARITY_ORDER[a.itemMeta.rarity]||0);
    return b.listed_at - a.listed_at; // newest
  });

  if(!filtered.length){
    el.innerHTML='<div style="color:#443333;font-size:.73rem;padding:8px">No items match your filters.</div>';
    return;
  }

  el.innerHTML = filtered.map(l=>{
    const item = l.itemMeta;
    const rc = RARITY_COLORS[item.rarity]||'#888';
    const isOwn = l.seller_id === getToken();
    return `<div class="market-row">
      <span style="font-size:1.3rem">${SLOT_ICONS[item.slot]||'📦'}</span>
      <div style="flex:1;min-width:0">
        <div style="font-size:.78rem;color:${rc};font-weight:500">${item.name}</div>
        <div style="font-size:.63rem;color:#553333">${(item.rarity||'').toUpperCase()} · +${item.passive||0} Ƒ/30min · ${l.seller_name||'Unknown'}</div>
      </div>
      <div style="text-align:right;flex-shrink:0">
        <div style="font-size:.85rem;color:#ff9900;font-weight:500">Ƒ${(l.price||0).toLocaleString()}</div>
        ${isOwn
          ? `<button onclick="cancelListing('${l.id}')" style="font-size:.62rem;background:none;border:1px solid #553333;color:#884444;padding:2px 7px;border-radius:3px;cursor:pointer;font-family:inherit;margin-top:3px">Cancel</button>`
          : `<button onclick="buyItem('${l.id}',${l.price})" style="font-size:.62rem;background:#0d0505;border:1px solid #ff6a0044;color:#ff9900;padding:2px 7px;border-radius:3px;cursor:pointer;font-family:inherit;margin-top:3px">Buy</button>`
        }
      </div>
    </div>`;
  }).join('');
};

window.buyItem = async function(listingId, price){
  const token = getToken(); if(!token) return;
  if(!confirm('Buy this item for Ƒ'+price.toLocaleString()+'?')) return;
  try{
    const r = await fetch('/api/items/market/buy',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,listingId})});
    const d = await r.json();
    if(d.ok){ try{showToast('Purchased: '+d.item?.name,'#1D9E75');}catch(_){} loadMarket(); loadInventory(); }
    else{ try{showToast('Purchase failed: '+d.error,'#ff4444');}catch(_){} }
  }catch(e){}
};

window.cancelListing = async function(listingId){
  const token = getToken(); if(!token) return;
  try{
    const r = await fetch('/api/items/market/cancel',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,listingId})});
    const d = await r.json();
    if(d.ok){ try{showToast('Listing cancelled','#888');}catch(_){} loadMarket(); loadInventory(); }
  }catch(e){}
};

window.showListForm = function(){
  const form = document.getElementById('listForm');
  if(form){ form.style.display = form.style.display==='none'?'block':'none'; }
  updateListSelect();
};

function updateListSelect(){
  const sel = document.getElementById('listInvSelect'); if(!sel) return;
  const equippedIds = new Set(Object.values(invState.equipped).filter(Boolean));
  const listable = invState.inventory.filter(i=>!equippedIds.has(i.invId));
  if(!listable.length){ sel.innerHTML='<option value="">No items available to list</option>'; return; }
  sel.innerHTML = listable.map(inv=>{
    const item = ITEM_CATALOG_CLIENT[inv.itemId]||{name:inv.itemId,rarity:'common'};
    return `<option value="${inv.invId}">[${item.rarity.toUpperCase()}] ${item.name}</option>`;
  }).join('');
}

window.submitListing = async function(){
  const token = getToken(); if(!token) return;
  const invId = document.getElementById('listInvSelect')?.value;
  const price = parseFloat(document.getElementById('listPrice')?.value);
  if(!invId){ try{showToast('Select an item','#ff9900');}catch(_){} return; }
  if(!price||price<=0){ try{showToast('Enter a valid price','#ff9900');}catch(_){} return; }
  try{
    const r = await fetch('/api/items/market/list',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,invId,price})});
    const d = await r.json();
    if(d.ok){ try{showToast('Item listed on market','#1D9E75');}catch(_){} document.getElementById('listForm').style.display='none'; loadMarket(); loadInventory(); }
    else{ try{showToast('List failed: '+d.error,'#ff4444');}catch(_){} }
  }catch(e){}
};

// ── WebSocket hooks ───────────────────────────────────────────────────────────
document.addEventListener('fm_ws_msg', e=>{
  const msg = e.detail; if(!msg) return;
  if(msg.type==='spin_grant'){
    const {spins,reason} = msg.data||{};
    invState.spins = (invState.spins||0) + (spins||0);
    updateSlotModalCount();
    try{ showToast(`+${spins} spin${spins>1?'s':''} granted! (${reason})`, '#ff9900'); }catch(_){}
  }
  if(msg.type==='milestone_update'){
    invState.milestoneTrades = msg.data?.milestoneTrades ?? invState.milestoneTrades;
    updateSlotModalCount();
  }
  if(msg.type==='spin_result'){
    invState.spins = msg.data?.spinsRemaining ?? invState.spins;
    updateSlotModalCount();
    // Guaranteed drops (monthly CEO grant, god command) show a toast wherever you are
    if(msg.data?.guaranteed){
      const item = msg.data.item;
      const rc = msg.data.rarityColor || '#ff6a00';
      try{ showToast(`🎁 ${item?.name||'Item'} dropped! (${(item?.rarity||'').toUpperCase()})`, rc); }catch(_){}
      loadInventory();
    }
  }
});

// Load inventory data when logged in
document.addEventListener('fm_login', ()=>{
  loadInventory();
});

// Also load if already logged in when script runs
if(window.ME && (window.ME.id || window.FM_TOKEN)){
  loadInventory();
}

